import java.io.*;
import java.util.*;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        String greetingMessage = "Hello, " + sanitizedInput + "! Welcome to our website!";

        System.out.println("<h1>" + greetingMessage + "</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
